// ── Utilidades ────────────────────────────────────────────────────────────────
const STROBE_COLS = ["#FF2D78","#FFD600","#9B2FFF","#00E5FF","#FF9500","#00F5A0","#FFFFFF","#FF2D78"];

function Orbs({ colors }) {
  return (
    <div className="orbs">
      {colors.map((c, i) => (
        <div key={i} className="orb" style={{
          width: [500,400,350][i%3], height: [500,400,350][i%3],
          background: c,
          top:  ["−10%","60%","30%"][i%3],
          left: ["−5%","70%","40%"][i%3],
          animationDuration: `${14+i*4}s`,
          animationDelay: `${i*3}s`,
          opacity: .7,
        }}/>
      ))}
    </div>
  );
}

function ConfettiPiece({ x, color, delay, size }) {
  return (
    <div className="confetti-piece" style={{
      left: x + "%", width: size, height: size * 1.5,
      background: color, opacity: .85,
      animationDuration: (2.5 + Math.random() * 2) + "s",
      animationDelay: delay + "s",
      transform: `rotate(${Math.random()*360}deg)`,
    }}/>
  );
}

function Confetti() {
  const pieces = Array.from({length: 80}, (_, i) => ({
    x: Math.random() * 100,
    color: STROBE_COLS[i % STROBE_COLS.length],
    delay: Math.random() * 1.5,
    size: 6 + Math.random() * 10,
  }));
  return <>{pieces.map((p, i) => <ConfettiPiece key={i} {...p}/>)}</>;
}

