// Escenario activo
function EscenarioScreen({ gameState }) {
  const type = gameState?.active_escenario || "duelo";
  const INFO = {
    duelo:   { label:"DUELO DE TALENTOS",   col:C.pink,   glow:"rgba(255,45,120,.4)",  sub:"Votá desde tu celular · Tu voto cuenta" },
    ftl:     { label:"FOLLOW THE LEADER",   col:C.amber,  glow:"rgba(255,149,0,.4)",   sub:"Seguí al líder · ¡Sube al escenario!" },
    pt:      { label:"PERSONAL TRAINER",    col:C.green,  glow:"rgba(0,245,160,.4)",   sub:"Modo gym · ¡Todos a moverse!" },
    karaoke: { label:"SI LO SABE CANTE",    col:C.purple, glow:"rgba(155,47,255,.4)",  sub:"El micrófono es tuyo" },
  };
  const info     = INFO[type] || INFO.duelo;
  const name     = gameState?.escenario_participant || null;
  const avatar   = gameState?.escenario_avatar     || "🎤";

  return (
    <div className="escenario" style={{position:"relative"}}>
      <Orbs colors={[`${info.col}22`,`${info.col}11`,"rgba(155,47,255,.05)"]}/>
      <div className="esc-tag" style={{color:info.col}}>{info.label}</div>
      {name ? (
        <>
          <div className="esc-avatar"
            style={{borderColor:info.col,boxShadow:`0 0 40px ${info.glow}`}}>
            {avatar}
          </div>
          <div className="esc-name" style={{
            background:`linear-gradient(135deg,${info.col},#F0E8FF)`,
            WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text"
          }}>{name}</div>
        </>
      ) : (
        <div style={{
          fontFamily:"Syne,sans-serif",fontWeight:900,
          fontSize:"clamp(60px,10vw,130px)",animation:"float 4s ease-in-out infinite"
        }}>{avatar}</div>
      )}
      <div className="esc-sub">{info.sub}</div>
    </div>
  );
}

